@patch("calendar_fetcher.__main__.metadata")
@patch("calendar_fetcher.__main__.exporter")
@patch("calendar_fetcher.__main__.calendar_client")
@patch("calendar_fetcher.__main__.check_auth_scopes")
def test_handle_fetch_processes_events(
    mock_check_auth, mock_calendar_client, mock_exporter, mock_metadata
):
    """Verify list_events called with correct date range, parse_event called.

    For each event, process_events called, build_and_write_index called.
    """
    from calendar_fetcher.__main__ import handle_fetch

    # Setup mocks
    mock_events = [{"id": "event1"}, {"id": "event2"}]
    mock_parsed_events = [{"event_id": "event1"}, {"event_id": "event2"}]
    mock_calendar_client.list_events.return_value = mock_events
    mock_calendar_client.parse_event.side_effect = mock_parsed_events
    mock_metadata.read_fetch_state.return_value = None

    # Create args
    args = argparse.Namespace(
        calendar_id="primary",
        output_dir="calendar-artifacts",
        lookback_days=7,
        date=None,
        drive_folder_id=None,
        dryrun=False,
        quiet=True,
    )

    # Execute
    handle_fetch(args)

    # Compute expected date range (no state file → anchor from today)
    today = date.today()
    lookback = today - timedelta(days=7)
    expected_time_min = f"{lookback.isoformat()}T00:00:00Z"
    expected_time_max = f"{today.isoformat()}T23:59:59Z"

    # Verify calls
    mock_check_auth.assert_called_once_with(upload=False)
    mock_calendar_client.list_events.assert_called_once_with(
        "primary", expected_time_min, expected_time_max
    )
    assert mock_calendar_client.parse_event.call_count == 2
    mock_calendar_client.parse_event.assert_any_call({"id": "event1"}, "primary")
    mock_calendar_client.parse_event.assert_any_call({"id": "event2"}, "primary")
    mock_exporter.process_events.assert_called_once_with(
        mock_parsed_events, Path("calendar-artifacts"), dryrun=False
    )
    mock_metadata.build_and_write_index.assert_called_once_with(
        Path("calendar-artifacts")
    )


