def test_handle_status_counts_files(tmp_path, capsys):
    """Create tmp_path with mock .meta.json files with artifacts.

    Verify output includes correct counts.
    """
    from calendar_fetcher.__main__ import handle_status

    # Create metadata files
    meta1 = tmp_path / "meeting1.meta.json"
    meta1.write_text(
        json.dumps(
            {
                "artifacts": [
                    {"local_file": "file1.pdf"},
                    {"local_file": "file2.pdf"},
                    {"local_file": None},
                ]
            }
        )
    )

    meta2 = tmp_path / "meeting2.meta.json"
    meta2.write_text(
        json.dumps(
            {
                "artifacts": [
                    {"local_file": "file3.pdf"},
                ]
            }
        )
    )

    meta3 = tmp_path / "meeting3.meta.json"
    meta3.write_text(json.dumps({"artifacts": []}))

    # Create args
    args = argparse.Namespace(output_dir=str(tmp_path))

    # Execute
    handle_status(args)

    # Verify output
    captured = capsys.readouterr()
    assert "Total meetings: 3" in captured.out
    assert "Total downloaded files: 3" in captured.out


